package com.baize.flux.connectors.jdbc;
import com.baize.flux.api.sink.SinkWriter; import com.baize.flux.api.table.*; import java.sql.*;
final class JdbcSinkWriter implements SinkWriter<FluxRow> { private final String url,user,password,table;private final int batchSize;private Connection connection;private PreparedStatement statement; JdbcSinkWriter(String u,String n,String p,String t,int b){url=u;user=n;password=p;table=t;batchSize=b;} public void open()throws SQLException{connection=DriverManager.getConnection(url,user,password);connection.setAutoCommit(false);} public void write(RecordBatch<FluxRow> batch)throws SQLException{for(FluxRow row:batch.records()){ensureStatement(row);for(int i=0;i<row.values().size();i++)statement.setObject(i+1,row.getField(i));statement.addBatch();} if(batch.records().size()>=batchSize)statement.executeBatch();} private void ensureStatement(FluxRow row)throws SQLException{if(statement!=null)return;StringBuilder sql=new StringBuilder("INSERT INTO ").append(table).append(" (");for(int i=0;i<row.rowType().fieldCount();i++){if(i>0)sql.append(',');sql.append(row.rowType().fieldNames().get(i));}sql.append(") VALUES (");for(int i=0;i<row.rowType().fieldCount();i++){if(i>0)sql.append(',');sql.append('?');}sql.append(')');statement=connection.prepareStatement(sql.toString());} public void flush()throws SQLException{if(statement!=null)statement.executeBatch();}public void commit()throws SQLException{connection.commit();}public void rollback()throws SQLException{if(connection!=null)connection.rollback();}public void close()throws SQLException{if(statement!=null)statement.close();if(connection!=null)connection.close();}}
